import{_ as s,o as a,c as p,ag as e}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/ESP-IDF-getting-started/8 GPIO实现Button控制LED灯亮灭/8.1什么是gpio_config_t结构体/index.md","filePath":"tutorials/ESP-IDF-getting-started/8 GPIO实现Button控制LED灯亮灭/8.1什么是gpio_config_t结构体/index.md","lastUpdated":null}'),i={name:"tutorials/ESP-IDF-getting-started/8 GPIO实现Button控制LED灯亮灭/8.1什么是gpio_config_t结构体/index.md"};function l(t,n,r,o,c,_){return a(),p("div",null,[...n[0]||(n[0]=[e(`<h2 id="📜-版权声明-apache-2-0" tabindex="-1">📜 版权声明 (Apache 2.0) <a class="header-anchor" href="#📜-版权声明-apache-2-0" aria-label="Permalink to &quot;📜 版权声明 (Apache 2.0)&quot;">​</a></h2><ul><li><strong>Copyright</strong>: 2026 MorkenMooooo</li><li><strong>Author</strong>: Mooooo (门主)</li><li><strong>平台</strong>: Bilibili &amp; Douyin &amp; 微信公众号 @ <strong>门主引擎 | Mooooo</strong></li><li><strong>taobao</strong>：<a href="https://item.taobao.com/item.htm?ft=t&amp;id=1045150620980" target="_blank" rel="noreferrer">https://item.taobao.com/item.htm?ft=t&amp;id=1045150620980</a></li><li><strong>联系</strong>: <a href="mailto:itsntcool@qq.com" target="_blank" rel="noreferrer">itsntcool@qq.com</a></li></ul><p>本项目采用 <strong>Apache License</strong>**, Version 2.0开源协议。 除非符合许可要求，否则不得使用本文件。 你可以在以下地址获取许可证副本： <a href="http://www.apache.org/licenses/LICENSE-2.0" target="_blank" rel="noreferrer">http://www.apache.org/licenses/LICENSE-2.0</a></p><p>除非适用法律要求或书面同意，否则本软件按“原样”分发，无任何明示或暗示的保证。</p><p>有关详细信息，请参阅许可证以了解特定语言管理的权限和限制。</p><h2 id="一、学习什么是gpio-config结构体配置" tabindex="-1">一、学习什么是gpio_config结构体配置？ <a class="header-anchor" href="#一、学习什么是gpio-config结构体配置" aria-label="Permalink to &quot;一、学习什么是gpio_config结构体配置？&quot;">​</a></h2><p><a href="https://documentation.espressif.com/projects/esp-idf/zh_CN/latest/esp32s3/api-reference/peripherals/gpio.html" target="_blank" rel="noreferrer">https://documentation.espressif.com/projects/esp-idf/zh_CN/latest/esp32s3/api-reference/peripherals/gpio.html</a></p><h3 id="_1-1-gpio-config-t结构体与io管脚配置有什么联系" tabindex="-1">1.1 gpio_config_t结构体与IO管脚配置有什么联系？ <a class="header-anchor" href="#_1-1-gpio-config-t结构体与io管脚配置有什么联系" aria-label="Permalink to &quot;1.1 gpio_config_t结构体与IO管脚配置有什么联系？&quot;">​</a></h3><p>IO 可以有两种使用方式：</p><ul><li>作为简单的 GPIO 输入读取引脚上的电平，或作为简单的 GPIO 输出以输出所需的电平。</li><li>作为外设信号的输入/输出。</li></ul><p>IDF 外设驱动内部会处理需要应用到引脚上的必要 IO 配置，以便它们可以用作外设信号的输入或输出。这意味着用户通常自己只需负责将 IO 配置为简单的输入或输出。<a href="https://documentation.espressif.com/projects/esp-idf/zh_CN/latest/esp32s3/api-reference/peripherals/gpio.html#_CPPv411gpio_configPK13gpio_config_t" target="_blank" rel="noreferrer">gpio_config()</a> 是一个一体化的 API，可用于配置 I/O 模式、内部上拉/下拉电阻等管脚设置，包括那些被 USB PHY 复用的引脚。</p><p>在一些应用中，IO 管脚可以同时发挥双重作用。例如，输出 LEDC PWM 信号的 IO 也可以作为 GPIO 输入生成中断或 GPIO ETM 事件。这种双重用途的 IO 管脚在配置时需要特别注意。由于 <a href="https://documentation.espressif.com/projects/esp-idf/zh_CN/latest/esp32s3/api-reference/peripherals/gpio.html#_CPPv411gpio_configPK13gpio_config_t" target="_blank" rel="noreferrer">gpio_config()</a> 是一个会覆盖所有当前配置的 API ，因此必须先调用它将管脚模式设置为 <a href="https://documentation.espressif.com/projects/esp-idf/zh_CN/latest/esp32s3/api-reference/peripherals/gpio.html#_CPPv4N11gpio_mode_t15GPIO_MODE_INPUTE" target="_blank" rel="noreferrer">gpio_mode_t::GPIO_MODE_INPUT</a>，然后才能调用 LEDC 驱动 API 将输出信号连接到引脚上。作为替代方案，如果除了使管脚输入启用之外不需要其他额外配置，可以随时调用 <a href="https://documentation.espressif.com/projects/esp-idf/zh_CN/latest/esp32s3/api-reference/peripherals/gpio.html#_CPPv417gpio_input_enable10gpio_num_t" target="_blank" rel="noreferrer">gpio_input_enable()</a> 以实现相同的目的。</p><h3 id="_1-2-如何认识gpio-config" tabindex="-1">1.2 如何认识gpio_config <a class="header-anchor" href="#_1-2-如何认识gpio-config" aria-label="Permalink to &quot;1.2 如何认识gpio_config&quot;">​</a></h3><p>esp_err_t gpio_config(const gpio_config_t *pGPIOConfig) GPIO common configuration.</p><p>Configure GPIO&#39;s Mode,pull-up,PullDown,IntrType 备注</p><p>This function always overwrite all the current IO configurations</p><p>参数: pGPIOConfig -- Pointer to GPIO configure struct</p><p>返回: ESP_OK success</p><p>ESP_ERR_INVALID_ARG Parameter error</p><hr><p>struct gpio_config_t</p><p>Configuration parameters of GPIO pad for gpio_config function.</p><p>Public Members</p><p>uint64_t pin_bit_mask</p><p>GPIO pin: set with bit mask, each bit maps to a GPIO</p><p><a href="https://documentation.espressif.com/projects/esp-idf/zh_CN/latest/esp32s3/api-reference/peripherals/gpio.html#_CPPv411gpio_mode_t" target="_blank" rel="noreferrer">gpio_mode_t</a> mode</p><p>GPIO mode: set input/output mode</p><p><a href="https://documentation.espressif.com/projects/esp-idf/zh_CN/latest/esp32s3/api-reference/peripherals/gpio.html#_CPPv413gpio_pullup_t" target="_blank" rel="noreferrer">gpio_pullup_t</a> pull_up_en</p><p>GPIO pull-up</p><p><a href="https://documentation.espressif.com/projects/esp-idf/zh_CN/latest/esp32s3/api-reference/peripherals/gpio.html#_CPPv415gpio_pulldown_t" target="_blank" rel="noreferrer">gpio_pulldown_t</a> pull_down_en</p><p>GPIO pull-down</p><p><a href="https://documentation.espressif.com/projects/esp-idf/zh_CN/latest/esp32s3/api-reference/peripherals/gpio.html#_CPPv415gpio_int_type_t" target="_blank" rel="noreferrer">gpio_int_type_t</a> intr_type</p><p>GPIO interrupt type</p><div class="language-plain vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/**</span></span>
<span class="line"><span> * @brief Configuration parameters of GPIO pad for gpio_config function</span></span>
<span class="line"><span> */</span></span>
<span class="line"><span>typedef struct {</span></span>
<span class="line"><span>    uint64_t pin_bit_mask;          /*!&lt; GPIO pin: set with bit mask, each bit maps to a GPIO */</span></span>
<span class="line"><span>    gpio_mode_t mode;               /*!&lt; GPIO mode: set input/output mode                     */</span></span>
<span class="line"><span>    gpio_pullup_t pull_up_en;       /*!&lt; GPIO pull-up                                         */</span></span>
<span class="line"><span>    gpio_pulldown_t pull_down_en;   /*!&lt; GPIO pull-down                                       */</span></span>
<span class="line"><span>    gpio_int_type_t intr_type;      /*!&lt; GPIO interrupt type                                  */</span></span>
<span class="line"><span>#if SOC_GPIO_SUPPORT_PIN_HYS_FILTER</span></span>
<span class="line"><span>    gpio_hys_ctrl_mode_t hys_ctrl_mode;       /*!&lt; GPIO hysteresis: hysteresis filter on slope input    */</span></span>
<span class="line"><span>#endif</span></span>
<span class="line"><span>} gpio_config_t;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h3 id="_1-3-如何使用gpio-config-t结构体" tabindex="-1">1.3 如何使用gpio_config_t结构体？ <a class="header-anchor" href="#_1-3-如何使用gpio-config-t结构体" aria-label="Permalink to &quot;1.3 如何使用gpio_config_t结构体？&quot;">​</a></h3><h4 id="方法-a-逐个赋值-推荐初学者" tabindex="-1">方法 A：逐个赋值（推荐初学者） <a class="header-anchor" href="#方法-a-逐个赋值-推荐初学者" aria-label="Permalink to &quot;方法 A：逐个赋值（推荐初学者）&quot;">​</a></h4><div class="language-plain vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gpio_config_t io_conf = {0};  // 先清零（重要！）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>io_conf.pin_bit_mask = (1ULL &lt;&lt; GPIO_NUM_2);  // 配置 GPIO2（注意用 1ULL 防止溢出）</span></span>
<span class="line"><span>io_conf.mode = GPIO_MODE_INPUT;               // 设为输入模式</span></span>
<span class="line"><span>io_conf.pull_up_en = GPIO_PULLUP_ENABLE;      // 启用上拉电阻</span></span>
<span class="line"><span>io_conf.pull_down_en = GPIO_PULLDOWN_DISABLE; // 禁用下拉</span></span>
<span class="line"><span>io_conf.intr_type = GPIO_INTR_DISABLE;        // 不使用中断</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h4 id="方法-b-初始化列表-更简洁" tabindex="-1">方法 B：初始化列表（更简洁） <a class="header-anchor" href="#方法-b-初始化列表-更简洁" aria-label="Permalink to &quot;方法 B：初始化列表（更简洁）&quot;">​</a></h4><div class="language-plain vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gpio_config_t io_conf = {</span></span>
<span class="line"><span>    .pin_bit_mask = (1ULL &lt;&lt; GPIO_NUM_2),</span></span>
<span class="line"><span>    .mode = GPIO_MODE_INPUT,</span></span>
<span class="line"><span>    .pull_up_en = GPIO_PULLUP_ENABLE,</span></span>
<span class="line"><span>    .pull_down_en = GPIO_PULLDOWN_DISABLE,</span></span>
<span class="line"><span>    .intr_type = GPIO_INTR_DISABLE,</span></span>
<span class="line"><span>};</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="_1-4-如何代码编写gpio-config-t结构体" tabindex="-1">1.4 如何代码编写gpio_config_t结构体？ <a class="header-anchor" href="#_1-4-如何代码编写gpio-config-t结构体" aria-label="Permalink to &quot;1.4 如何代码编写gpio_config_t结构体？&quot;">​</a></h3><div class="language-plain vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>#include &lt;stdio.h&gt;</span></span>
<span class="line"><span>#include &quot;driver/gpio.h&quot;</span></span>
<span class="line"><span>#include &quot;freertos/FreeRTOS.h&quot;</span></span>
<span class="line"><span>#include &quot;freertos/task.h&quot;</span></span>
<span class="line"><span>#include &quot;driver/spi_master.h&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>void app_main(void)</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    gpio_config_t my_led_pin_config = {0};</span></span>
<span class="line"><span>    my_led_pin_config.pin_bit_mask = (1ULL &lt;&lt; GPIO_NUM_2) | (1ULL &lt;&lt; GPIO_NUM_4);</span></span>
<span class="line"><span>    my_led_pin_config.mode = GPIO_MODE_OUTPUT;</span></span>
<span class="line"><span>    my_led_pin_config.pull_up_en = GPIO_PULLUP_DISABLE;</span></span>
<span class="line"><span>    my_led_pin_config.pull_down_en = GPIO_PULLDOWN_DISABLE;</span></span>
<span class="line"><span>    my_led_pin_config.intr_type = GPIO_INTR_DISABLE;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    gpio_config(&amp;my_led_pin_config);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    gpio_set_level(GPIO_NUM_2, 1);</span></span>
<span class="line"><span>    gpio_set_level(GPIO_NUM_4, 1);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    spi_bus_config_t my_spi_bus = {0};</span></span>
<span class="line"><span></span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br></div></div>`,41)])])}const b=s(i,[["render",l]]);export{g as __pageData,b as default};
